import sys
from collections import defaultdict
class TrieNode:
    def __init__(self):
        self.isEndOfWord = False
        self.children = defaultdict(lambda: None)

class Solution:
    def autoCompletion(self, words, input):
        root = TrieNode()
        for word in words:
            cur = root
            for c in word:
                if not cur.children[c - ord('a')]:
                    cur.children[c - ord('a')] = TrieNode()
                cur = cur.children[c - ord('a')]
            cur.isEndOfWord = True
        cur = root
        for c in input:
            if c == '\0':
                return []
            c = c - ord('a')
            if not cur.children[c]:
                return []
            cur = cur.children[c]
        autoCompletion = set()
        self.autoComplete(cur, input, '')
        return list(autoCompletion)

    def autoComplete(self, cur, input, prefix):
        if cur.isEndOfWord:
            autoCompletion.add(prefix)
        for i in range(26):
            if cur.children[i] is not None:
                self.autoComplete(cur.children[i], input, prefix + chr(i + ord('a')))

def main():
    words = sys.stdin.readline().split('
')[0].split('
')
    input = sys.stdin.readline().split('
')[1].split('
')[0]\
    solution = Solution()
    autoCompletion = solution.autoCompletion(words, input)\
    print('
'.join(autoCompletion))
if __name__ == '__main__':
    main()

